import { FC, Fragment } from 'react';

import { ItemsProps, ItemProps } from '../PriceComparison.types';

import { List } from './Items.styles';

const Items: FC<ItemsProps> = ({ items, renderItems }) => (
  <List>
    {items.map((item: ItemProps, i: number) => (
      <Fragment key={`price-comparison-${i}`}>{renderItems(item)}</Fragment>
    ))}
  </List>
);

export default Items;
