/**
 * A custom hook to fetch data from a URL, and return the data, loading state, or error
 *
 * State starts with initial step, then goes to loading, success, or error
 * otherwise if there is an error, it returns the default data from props
 *
 * uses useCallback to memoize the function so it doesn't change on every render
 * uses useReducer to manage the state
 */
import { useReducer, useEffect, useCallback } from 'react';

export const enum Step {
  INITIAL = 'initial',
  LOADING = 'loading',
  SUCCESS = 'success',
  ERROR = 'error',
}

type State = {
  step: Step;
  data: unknown;
  error?: string;
};

type Action =
  | { type: Step.LOADING }
  | { type: Step.SUCCESS; payload: unknown }
  | { type: Step.ERROR; payload: string };

const reducer = (state: State, action: Action): State => {
  switch (action.type) {
    case Step.LOADING:
      return { step: Step.LOADING, data: state.data };
    case Step.SUCCESS:
      return { step: Step.SUCCESS, data: action.payload };
    case Step.ERROR:
      return {
        step: Step.ERROR,
        data: state.data,
        error: action.payload || 'Unknown error',
      };
    default:
      return state;
  }
};

export type ResponseTransformer = (data: unknown) => unknown;

type Options = {
  url: string;
  initialData: unknown;
  triggerFetch?: boolean;
  responseTransformer?: ResponseTransformer;
};

interface Return extends State {
  fetchData: () => Promise<unknown>;
}

export const useFetch = ({
  url,
  initialData,
  triggerFetch = false,
  responseTransformer,
}: Options): Return => {
  const [{ step, data, error }, dispatch] = useReducer(reducer, {
    step: Step.INITIAL,
    data: initialData,
  });

  const fetchData = useCallback(async () => {
    dispatch({ type: Step.LOADING });

    try {
      const response = await fetch(url);

      if (!response.ok) {
        throw new Error(response.statusText, { cause: response });
      }

      const data = await response.json();
      const payload = responseTransformer ? responseTransformer(data) : data;

      dispatch({ type: Step.SUCCESS, payload });
    } catch (error) {
      if (error instanceof Error) {
        dispatch({
          type: Step.ERROR,
          payload: error.message,
        });
      }
    }
  }, [url, responseTransformer]);

  useEffect(() => {
    triggerFetch && fetchData();
  }, [fetchData, triggerFetch]);

  return { step, data, error, fetchData };
};
