import { FC } from 'react';

export const getPriceWithoutDecimals = (price: string) => price.split('.')[0];

import { PriceComparisonProps, ItemProps } from './PriceComparison.types';
import PriceComparisonAsList from './PriceComparisonAsList';

import { useFetch, Step } from '#hooks/useFetch';

const PriceComparison: FC<PriceComparisonProps> = ({
  className,
  endpoint,
  productName,
  vendorName,
  vendorLink,
  prettyPrice,
  responseTransformer,
  initialFetch = false,
  Component = PriceComparisonAsList,
}) => {
  const initialData: ItemProps[] = [
    {
      merchant: vendorName,
      link: vendorLink,
      price: getPriceWithoutDecimals(prettyPrice),
    },
  ];

  const { step, data, error } = useFetch({
    url: endpoint,
    initialData,
    triggerFetch: initialFetch,
    responseTransformer,
  });

  const items: ItemProps[] = data as ItemProps[];
  const isLoading = step === Step.INITIAL || step === Step.LOADING;
  const hasError = step === Step.ERROR;
  const hasNoData = step === Step.SUCCESS && (items?.length === 0 || !data);
  const isFallback = hasNoData || hasError;

  if (isFallback) {
    error && console.warn(error);
  }

  return (
    <Component
      className={className}
      productName={productName}
      items={isFallback ? initialData : items}
      isLoading={isLoading}
      isFallback={isFallback}
    />
  );
};

export default PriceComparison;
