import { FC, useState } from 'react';

import { SIZE_SMALL as ICON_SIZE_SMALL } from '#components/Icon/Icon.constants';

import Items from '../Items';
import { TITLE, OFFERS_LIMIT, SHOW_MORE } from '../PriceComparison.constants';
import {
  ItemProps,
  PriceComparisonComponentProps,
} from '../PriceComparison.types';

import Fallback from './Fallback';
import Item from './Item';
import Loading from './Loading';
import {
  Boundary,
  Title,
  Content,
  CustomDropdown,
  ShowMore,
  ChevronIcon,
} from './PriceComparisonAsList.styles';

import ChevronDownSvg from '#icons/chevron-down-solid-16.svg';

const PriceComparisonAsList: FC<PriceComparisonComponentProps> = ({
  productName = '',
  items,
  isLoading,
  isFallback,
}) => {
  /**
   * @todo only employ dropdown when the component is within the viewport when
   * it loads, otherwise setIsOpen(false)
   */
  const [isOpen, setIsOpen] = useState(items?.length < OFFERS_LIMIT);
  const onInteract = () => setIsOpen((isOpen) => !isOpen);
  const title = `${TITLE} ${productName}`;
  const isSingleItem = items?.length === 1;

  const ItemsComponent = () => (
    <Items
      items={items}
      renderItems={({ merchant, price, link }: ItemProps) => {
        return <Item merchant={merchant} price={price} link={link} />;
      }}
    />
  );

  if (isLoading) {
    return <Loading />;
  }

  if (isFallback) {
    return <Fallback title={title} Component={ItemsComponent} />;
  }

  return (
    <Boundary>
      <Title>{title}</Title>
      {isSingleItem ? (
        <Content>
          <ItemsComponent />
        </Content>
      ) : (
        <CustomDropdown
          isOpen={isOpen}
          onInteract={onInteract}
          trigger={
            <ShowMore>
              {SHOW_MORE}
              <ChevronIcon svg={ChevronDownSvg} size={ICON_SIZE_SMALL} />
            </ShowMore>
          }
        >
          <ItemsComponent />
        </CustomDropdown>
      )}
    </Boundary>
  );
};

export default PriceComparisonAsList;
